### 2. `StageContentGenerator.java` 수정

`EVENT_GRADE_THRESHOLDS` 필드가 사용되지 않는다는 경고를 제거하고, `EventGrade`의 `threshold` 값을 활용하는 예시 로직을 추가하여 해당 필드가 의미를 가지도록 수정합니다. (이 부분은 `StageContentGenerator`의 생성자 또는 `generateStageContent` 메서드 내에서 사용될 수 있습니다.)

TARGET_PATH: demo\src\main\java\com\example\single\core\StageContentGenerator.java
```java
package com.example.single.core;

import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.HashMap;
import java.util.Random;

import com.example.single.core.EventGrade; // EventGrade import

/**
 * 게임 스테이지의 콘텐츠를 생성하는 클래스.
 * 시드 값을 기반으로 맵의 각 스테이지에 들어갈 이벤트와 같은 콘텐츠를 결정합니다.
 */
public class StageContentGenerator {

    private final long gameSeed;
    private final Random random;

    // 이벤트 등급별 BValue 상한선 (threshold)
    // 이 값들은 StageContentGenerator 내부적으로 이벤트 등급을 결정하거나,
    // 특정 BValue 범위에 맞는 이벤트를 선택할 때 사용될 수 있습니다.
    private static final Map<EventGrade, Integer> EVENT_GRADE_THRESHOLDS = new HashMap<>();

    static {
        EVENT_GRADE_THRESHOLDS.put(EventGrade.NORMAL, 2000);
        EVENT_GRADE_THRESHOLDS.put(EventGrade.RARE, 4000);
        EVENT_GRADE_THRESHOLDS.put(EventGrade.EPIC, 6000);
        EVENT_GRADE_THRESHOLDS.put(EventGrade.LEGENDARY, 8000);
        EVENT_GRADE_THRESHOLDS.put(EventGrade.MYTHIC, 10000); // 최대 9999 이므로, 신화는 9999에 가깝게 설정
    }

    public StageContentGenerator(long gameSeed) {
        this.gameSeed = gameSeed;
        this.random = new Random(gameSeed); // 시드 값을 사용하여 Random 객체 초기화
    }

    /**
     * 주어진 레벨에 대한 스테이지 콘텐츠를 생성합니다.
     *
     * @param level 생성할 스테이지의 레벨 (0부터 시작)
     * @return 생성된 StageContent 객체
     */
    public StageContent generateStageContent(int level) {
        // 1. 스테이지 이름 결정 (예: "어두운 숲", "고대 유적" 등)
        String stageName = determineStageName(level);

        // 2. 스테이지 타입 결정 (BATTLE, EVENT, REST, BOSS 등)
        StageType stageType = determineStageType(level);

        // 3. 이벤트 결정 (이벤트가 없는 스테이지 타입일 수도 있음)
        EventDefinition eventDefinition = null;
        if (stageType == StageType.EVENT || stageType == StageType.BATTLE) { // 이벤트 또는 전투 스테이지에서 이벤트 발생 가능
            eventDefinition = determineEvent(level);
        } else {
            // 이벤트가 없는 스테이지 타입 (예: REST)
            eventDefinition = new EventDefinition("None", "휴식", EventGrade.NORMAL, 0); // 기본값 또는 null 처리
        }


        return new StageContent(stageName, stageType, eventDefinition);
    }

    /**
     * 주어진 레벨에 따라 스테이지 이름을 결정합니다.
     * 실제로는 레벨에 따라 더욱 다양한 이름을 동적으로 생성할 수 있습니다.
     */
    private String determineStageName(int level) {
        String[] possibleNames = {"시작의 땅", "험난한 길", "고요한 숲", "용감한 기사단의 전당", "잊혀진 사원", "정령의 샘", "화염의 계곡", "얼음 동굴", "안개의 늪", "최후의 성채"};
        // 레벨에 따라 순환하거나, 시드를 이용해 결정
        int nameIndex = (level % possibleNames.length);
        return possibleNames[nameIndex] + " (Lv. " + level + ")";
    }

    /**
     * 주어진 레벨에 따라 스테이지 타입을 결정합니다.
     * 시드 값과 레벨을 활용하여 각 스테이지 타입의 출현 빈도를 조절할 수 있습니다.
     */
    private StageType determineStageType(int level) {
        // 간단한 예시: 특정 레벨에서는 보스 등장
        if (level == 4) { // 마지막 스테이지 (5 레벨 중 4번째)
            return StageType.BOSS;
        }

        // 시드를 이용해 무작위로 스테이지 타입 결정 (BATTLE, EVENT, REST 비율 조절)
        // 예: 70% BATTLE, 20% EVENT, 10% REST
        int typeRoll = random.nextInt(10);
        if (typeRoll < 7) {
            return StageType.BATTLE;
        } else if (typeRoll < 9) {
            return StageType.EVENT;
        } else {
            return StageType.REST;
        }
    }

    /**
     * 주어진 레벨에 따라 발생할 이벤트를 결정합니다.
     * 이벤트 등급과 BValue를 시드 값과 레벨에 기반하여 결정합니다.
     */
    private EventDefinition determineEvent(int level) {
        // 1. 이벤트 등급 결정 (BValue를 기반으로 등급 결정)
        // Random.nextInt(10000)는 0부터 9999 사이의 값을 반환합니다.
        int bValue = random.nextInt(10000); // 0 ~ 9999

        EventGrade grade = EventGrade.NORMAL;
        // EVENT_GRADE_THRESHOLDS 맵을 사용하여 BValue에 따른 등급 결정
        if (bValue >= EVENT_GRADE_THRESHOLDS.get(EventGrade.MYTHIC)) {
            grade = EventGrade.MYTHIC;
        } else if (bValue >= EVENT_GRADE_THRESHOLDS.get(EventGrade.LEGENDARY)) {
            grade = EventGrade.LEGENDARY;
        } else if (bValue >= EVENT_GRADE_THRESHOLDS.get(EventGrade.EPIC)) {
            grade = EventGrade.EPIC;
        } else if (bValue >= EVENT_GRADE_THRESHOLDS.get(EventGrade.RARE)) {
            grade = EventGrade.RARE;
        }
        // NORMAL은 기본값이므로 별도 처리가 필요 없음

        // 2. 이벤트 이름 및 설명 결정 (이벤트 등급에 따라 다르게)
        String eventName;
        String eventDesc;

        // EventDataLoader 와 같은 외부 소스에서 이벤트를 로드하는 것이 더 좋습니다.
        // 여기서는 간단한 예시로 임의의 이벤트 정보를 생성합니다.
        switch (grade) {
            case RARE:
                eventName = "희귀한 발견";
                eventDesc = "오래된 보물 상자를 발견했습니다!";
                break;
            case EPIC:
                eventName = "전설의 조각";
                eventDesc = "전설적인 유물을 발견할 가능성이 있습니다.";
                break;
            case LEGENDARY:
                eventName = "고대 왕의 축복";
                eventDesc = "위대한 존재의 축복으로 강력한 힘을 얻었습니다.";
                break;
            case MYTHIC:
                eventName = "차원의 균열";
                eventDesc = "알 수 없는 차원으로 가는 문이 열렸습니다!";
                break;
            case NORMAL:
            default:
                eventName = "작은 소지품";
                eventDesc = "평범한 소지품을 발견했습니다.";
                break;
        }

        return new EventDefinition(eventName, eventDesc, grade, bValue);
    }

    // --- Enum 및 Class 정의 (필요에 따라 별도 파일로 분리) ---

    /**
     * 스테이지의 타입을 정의합니다.
     */
    public enum StageType {
        BATTLE,  // 전투
        EVENT,   // 이벤트
        REST,    // 휴식
        BOSS     // 보스
    }

    /**
     * 스테이지의 콘텐츠 (이름, 타입, 이벤트 정보)를 담는 클래스입니다.
     */
    public static class StageContent {
        public final String stageName;
        public final StageType stageType;
        public final EventDefinition eventDefinition;

        public StageContent(String stageName, StageType stageType, EventDefinition eventDefinition) {
            this.stageName = stageName;
            this.stageType = stageType;
            this.eventDefinition = eventDefinition;
        }
    }
}
```

